      clauses: list[str] = []
      for subj, phrases in subject_phrases.items():
          if len(phrases) == 1:
              clauses.append(f"{subj} {phrases[0]}")
          else:
              # Oxford comma before the last phrase of this subject
              clauses.append(f"{subj} " + ", ".join(phrases[:-1]) + ", and " + phrases[-1])
      # Join subject clauses with semicolons for readability and end with a period
      sentence = "; ".join(clauses) + "."
      return sentence
